<?php
namespace App\Services;use App\Models\Employee;use Illuminate\Support\Facades\DB;
class ApprovalRouter{public function firstApprover(string$module,?Employee$employee):?int{$workflow=DB::table('approval_workflows')->where('module',$module)->where('is_active',true)->where(fn($q)=>$q->where('company_id',$employee?->company_id)->orWhereNull('company_id'))->orderByDesc('company_id')->first();if(!$workflow)return null;$step=DB::table('approval_workflow_steps')->where('approval_workflow_id',$workflow->id)->orderBy('sequence')->first();if(!$step)return null;if($step->approver_type==='user')return$step->user_id;if($step->approver_type==='manager')return$employee?->department?->manager_id;return DB::table('users')->where('role_id',$step->role_id)->where('is_active',true)->value('id');}}
